import{_ as t,g as a,f as h,z as i}from"./chunks/framework.pU9sRy1K.js";const m=JSON.parse('{"title":"Bổn Sanh — Chuyện Tiền Thân số 1","description":"Câu chuyện tiền thân đầu tiên trong 547 chuyện Bổn Sanh.","frontmatter":{"code":"BS. 1","title":"Bổn Sanh — Chuyện Tiền Thân số 1","pali":"Jātaka 1: Apaṇṇaka","group":"Truyện & Trưởng lão kệ","translation":"thich-minh-chau","book":"tieu-bo","description":"Câu chuyện tiền thân đầu tiên trong 547 chuyện Bổn Sanh."},"headers":[],"relativePath":"kinh/tieu-bo/thich-minh-chau/jat-1-bon-sanh.md","filePath":"kinh/tieu-bo/thich-minh-chau/jat-1-bon-sanh.md","lastUpdated":1782983601000}'),o={name:"kinh/tieu-bo/thich-minh-chau/jat-1-bon-sanh.md"};function u(c,n,e,r,g,p){return a(),h("div",null,[...n[0]||(n[0]=[i('<h2 id="chuyen-tien-than-so-1-—-apannaka" tabindex="-1">Chuyện tiền thân số 1 — Apaṇṇaka <a class="header-anchor" href="#chuyen-tien-than-so-1-—-apannaka" aria-label="Permalink to “Chuyện tiền thân số 1 — Apaṇṇaka”">​</a></h2><p><em>Như vầy tôi nghe.</em></p><p>Ngày xưa, khi Đức Phật Vipassī còn tại thế, Bồ-tát sanh làm con trai của vua Kāsi, tên là Brahmadatta. Khi lên ngôi, Ngài cai trị đất nước bằng chánh pháp, không dùng gươm giáo.</p><p>Một hôm, vua của đất nước láng giềng xâm lược. Vua Brahmadatta triệu tập các bậc thần, bà con hoàng tộc và hỏi:</p><blockquote><p>&quot;Nên chiến đấu để bảo vệ vương quốc, hay nên nhường nhịn để tránh đổ máu dân lành?&quot;</p></blockquote><p>Sau khi bàn bạc, vua quyết định rời kinh thành cùng gia quyến, đi vào rừng sâu. Trên đường trốn chạy, đoàn người gặp một con sông lớn không có bến đò. Vua bảo mọi người dựng bè bằng tre nứa, vượt qua an toàn.</p><p>Khi đến bờ bên kia, một người trong đoàn nói: &quot;Chúng ta đã qua sông nhờ phước báu của vua.&quot; Vua đáp: &quot;Không phải nhờ ta, mà nhờ sự kiên nhẫn và đoàn kết của tất cả.&quot;</p><p>Đó là lý do chuyện này được gọi là <em>Apaṇṇaka</em> — &quot;không bao giờ thất bại&quot; — vì những ai hành động với trí tuệ và từ bi sẽ vượt qua mọi hiểm nguy.</p><hr>',9)])])}const l=t(o,[["render",u]]);export{m as __pageData,l as default};
